queries.sparql:
PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?familysuites a :FamilySuites .
    ?familysuites p:Room ?room .
    BIND(?room AS ?o0)
  }
  UNION
  {
    ?singlerooms a :SingleRooms .
    ?singlerooms p:Room ?room .
    ?singlerooms p:Price_per_night ?price_per_night_f .
    FILTER((STR(?price_per_night_f) = "150" || STR(?price_per_night_f) = "150.0"))
    BIND(?room AS ?o0)
  }
}

